    def describe_topics(self, topic_names: Optional[List[str]] = None) -> Dict[str, Any]:
        """
        Describe topics with partition and replica information.

        Args:
            topic_names: List of topic names to describe. If None, describes all topics.

        Returns:
            Dictionary with topic descriptions
        """
        try:
            if topic_names is None:
                topic_names = self.list_topics()

            descriptions = self.admin_client.describe_topics(topic_names)
            result = {}

            for desc in descriptions:
                topic_name = desc.get("topic", "unknown")
                partitions_info = []

                for partition in desc.get("partitions", []):
                    partition_info = {
                        "partition_id": partition.get("partition", -1),
                        "leader": partition.get("leader", -1),
                        "replicas": partition.get("replicas", []),
                        "isr": partition.get("isr", []),
                    }
                    partitions_info.append(partition_info)

                result[topic_name] = {
                    "topic": topic_name,
                    "partitions": len(partitions_info),
                    "partition_details": sorted(
                        partitions_info, key=lambda x: x["partition_id"]
                    ),
                    "is_internal": desc.get("is_internal", False),
                }

            return result
        except KafkaError as e:
            logger.error("Failed to describe topics: %s", e)
            return {}

    def add_partitions(self, topic_name: str, total_partitions: int) -> bool:
        """
        Increase the number of partitions for a topic.

        Note: Kafka only supports increasing partitions, not decreasing.

        Args:
            topic_name: Name of the topic
            total_partitions: New total number of partitions (must be greater than current)

        Returns:
            True if partitions were added successfully
        """
        try:
            # First check current partition count
            topic_desc = self.describe_topics([topic_name])
            if topic_name not in topic_desc:
                logger.error("Topic '%s' not found.", topic_name)
                return False

            current_partitions = topic_desc[topic_name]["partitions"]
            if total_partitions <= current_partitions:
                logger.error(
                    "New partition count (%d) must be greater than current count (%d) for topic '%s'.",
                    total_partitions,
                    current_partitions,
                    topic_name,
                )
                return False

            partition_update = {topic_name: NewPartitions(total_count=total_partitions)}
            self.admin_client.create_partitions(partition_update)
            logger.info(
                "Partitions for topic '%s' increased from %d to %d.",
                topic_name,
                current_partitions,
                total_partitions,
            )
            return True
        except KafkaError as e:
            logger.error(
                "Failed to add partitions to topic '%s': %s", topic_name, e
            )
            return False

    def describe_topic_config(self, topic_name: str) -> Dict[str, str]:
        """
        Get the configuration for a topic.

        Args:
            topic_name: Name of the topic

        Returns:
            Dictionary of configuration key-value pairs
        """
